sql:
SELECT c.client_name
FROM clients c
JOIN risk_assessments ra ON c.client_id = ra.client_id
WHERE ra.score = (
    SELECT MAX(score) FROM risk_assessments
);

SELECT client_id, COUNT(*) AS total_assessments
FROM risk_assessments
GROUP BY client_id;

SELECT AVG(score) AS average_score
FROM risk_assessments
WHERE client_id = 1;

SELECT recommendation_id
FROM recommendations
WHERE status = 'pending';

SELECT client_name
FROM clients
WHERE client_id != (SELECT MIN(client_id) FROM clients);

SELECT upload_id, upload_date, file_path
FROM data_uploads
WHERE upload_date > '2022-10-01';

SELECT DISTINCT clients.client_name, data_uploads.file_type
FROM clients
JOIN data_uploads ON clients.client_id = data_uploads.client_id;

SELECT clients.client_name, risk_assessments.risk_level
FROM clients
JOIN risk_assessments ON clients.client_id = risk_assessments.client_id;

SELECT DISTINCT r.recommendation
FROM recommendations r
JOIN risk_assessments ra ON r.assessment_id = ra.assessment_id;
